-- Pattern 1: N+1 query anti-pattern

-- BAD (pseudocode): 100 users → 101 queries.
-- for user in db.query('SELECT * FROM users LIMIT 100'):
--     orders = db.query('SELECT * FROM orders WHERE user_id = ' + user.id)

-- GOOD: one join.
SELECT u.*, o.id AS oid, o.total
FROM users u LEFT JOIN orders o ON o.user_id = u.id
WHERE u.id IN (SELECT id FROM users LIMIT 100);

-- Pattern 2: EXISTS vs IN

-- SLOW: IN with subquery (may materialize the whole list):
SELECT * FROM users WHERE id IN (SELECT user_id FROM orders WHERE status = 'paid');

-- FAST: EXISTS (short-circuits per user):
SELECT * FROM users u WHERE EXISTS (
    SELECT 1 FROM orders o WHERE o.user_id = u.id AND o.status = 'paid'
);

-- Pattern 3: SELECT * vs specific columns

-- BAD: fetches everything (defeats covering indexes; more network).
SELECT * FROM orders WHERE user_id = 42;

-- GOOD: fetches only what you use (may allow Index Only Scan).
SELECT id, total FROM orders WHERE user_id = 42;

-- Pattern 4: LIMIT without ORDER BY is ambiguous — always specify order.
SELECT * FROM orders ORDER BY created_at DESC LIMIT 20;

-- Pattern 5: OFFSET pagination is O(N)

-- SLOW: skips 10000 rows for page 500.
SELECT * FROM orders ORDER BY id LIMIT 20 OFFSET 10000;

-- FAST — keyset / cursor pagination:
SELECT * FROM orders WHERE id > $last_seen_id ORDER BY id LIMIT 20;

-- Pattern 6: Function on indexed column disables the index.

-- BAD:
SELECT * FROM orders WHERE DATE(created_at) = '2026-06-01';

-- GOOD:
SELECT * FROM orders WHERE created_at >= '2026-06-01' AND created_at < '2026-06-02';

-- Pattern 7: ORDER BY random() is disaster on big tables.
-- SLOW: sorts entire table.
SELECT * FROM users ORDER BY RANDOM() LIMIT 10;

-- FAST: TABLESAMPLE (Postgres).
SELECT * FROM users TABLESAMPLE SYSTEM (0.1) LIMIT 10;
